const e={bridges:{en:"Bridges",zh:"桥接"},addBridge:{en:"Add Bridge",zh:"添加桥接"},droppedSentMessages:{en:"Dropped / Sent msg num",zh:"丢弃 / 发送消息数"},droppedReceivedMessages:{en:"Dropped / Received msg num",zh:"丢弃 / 接收消息数"},reconnectTimes:{en:"Reconnect times",zh:"重连次数"},connection:{en:"Connection",zh:"连接"},forwards:{en:"Forwards",zh:"转发"},bridgeStatus:{en:"Bridge status",zh:"桥接状态"},maxParallelProcesses:{en:"Max parallel processes",zh:"最大并行进程数"},maxParallelProcessesConfTip:{en:"The max parallel processes will take effect and be displayed on the dashboard after restarting EMQX Edge.",zh:"更新的最大并行进程数将在重启 EMQX Edge 后生效并显示在面板上"},remoteTopic:{en:"Remote topic",zh:"远程主题"},localTopic:{en:"Local topic",zh:"本地主题"},finishConnectorFirst:{en:"Please configure the connection first",zh:"请先正确配置连接"},tips:{en:"Tips",zh:"提示"},addBridgeTip:{en:"The added bridge will take effect and be displayed in the bridge list after restarting EMQX Edge",zh:"添加的桥接将在重启 EMQX Edge 后生效并显示在桥接列表中"},noMoreRemind:{en:"No more remind",zh:"不再提醒"},forwardsOrSubscriptionsRequired:{en:"Please configure at least one forwarding rule or subscription",zh:"请至少配置一条转发规则或订阅"},bridgeNameExists:{en:"Bridge name already exists",zh:"桥接名称已存在"},deleteBridgeConfirm:{en:"Confirm to delete bridge {name}?",zh:"是否确认删除桥接 {name}？"},bridgeNameNotExists:{en:"Bridge name not exists",zh:"桥接名称不存在"},deleteBridgeTip:{en:"The deleted bridge will lose effect and be removed from the bridge list after restarting EMQX Edge",zh:"删除的桥接将在重启 EMQX Edge 后失效并从桥接列表中移除"},portRequired:{en:"Please enter the server address in the format of example.com:port",zh:"请输入由 IP 地址和端口号组成的地址，例如 example.com:1883"},forwardQosTip:{en:"When empty, the original QoS will be forwarded",zh:"为空时则按原 QoS 转发"},cachedMsgSize:{en:"Cached msg size",zh:"缓存消息大小"},totalPayloadSizeOfCachedMsgInMemory:{en:"Total payload size of cached msg in memory",zh:"内存中缓存消息总 Payload 大小"},cachedMsgNum:{en:"Cached msg num",zh:"缓存消息数"},countAllCachedMsgInSqlite:{en:"Count all cached msg in SQLite",zh:"SQLite 中缓存消息总数"},resetPassword:{en:"Reset Password",zh:"重置密码"},quicKeepalive:{en:"Keep Alive Interval",zh:"心跳间隔"},quicIdleTimeout:{en:"Idle Timeout",zh:"空闲超时"},quicDisconTimeout:{en:"Disconnect Timeout",zh:"断连超时"},quicHandshakeTimeout:{en:"Handshake Timeout",zh:"握手超时"},quicSendIdleTimeout:{en:"Send Idle Timeout",zh:"发送空闲超时"},quicInitialRttMs:{en:"Initial RTT",zh:"初始往返时延"},quicInitialRttMsDesc:{en:"Initial Round-Trip Time estimate. Used to calculate timeout and congestion control parameters during initial connection. Adjust based on actual network conditions.",zh:"初始往返时延（RTT）估算值。用于在连接建立初期计算超时和拥塞控制参数。建议根据实际网络环境调整。"},quicMaxAckDelayMs:{en:"Max ACK Delay",zh:"最大确认延迟"},quicQosPriority:{en:"QoS Priority",zh:"QoS 优先级"},quicQosPriorityDesc:{en:"When enabled, QoS 1/2 messages are sent with higher priority. QoS 0 messages remain unchanged. Recommended when network congestion is expected.",zh:"启用后，QoS 1/2 的消息将以更高优先级发送，QoS 0 消息优先级不变。建议在网络拥塞时启用。"},quic_0rtt:{en:"0-RTT Resumption",zh:"0-RTT 快速重连"},quic_0rttDesc:{en:"Enable QUIC 0-RTT feature, allowing the client to send data immediately upon reconnection without waiting for handshake completion. Significantly reduces reconnection latency.",zh:"启用 QUIC 0-RTT 特性，允许客户端在重新连接时立即发送数据，无需等待握手完成。可显著减少重连延迟。"},quicConfig:{en:"QUIC Configuration",zh:"QUIC 配置"},quicTlsRequired:{en:"QUIC must enable TLS configuration",zh:"QUIC 必须开启 TLS 配置"}};export{e as default};
